    /**
     * @method
     * @name bitmart#fetchMarkets
     * @description retrieves data on all markets for bitmart
     * @see https://developer-pro.bitmart.com/en/spot/#get-trading-pair-details-v1
     * @see https://developer-pro.bitmart.com/en/futuresv2/#get-contract-details
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.GetValue(this.options, "adjustForTimeDifference")))
            {
                (this.loadTimeDifference()).join();
            }
            Object spotPromise = this.fetchSpotMarkets(parameters);
            Object contractPromise = this.fetchContractMarkets(parameters);
            var spotcontractVariable = (Helpers.promiseAll(new java.util.ArrayList<Object>(java.util.Arrays.asList(spotPromise, contractPromise)))).join();
            var spot = ((java.util.List<Object>) spotcontractVariable).get(0);
            var contract = ((java.util.List<Object>) spotcontractVariable).get(1);
            return this.arrayConcat(spot, contract);
        });

    }

    /**
     * @method
     * @name bitmart#fetchCurrencies
     * @description fetches all available currencies on an exchange
     * @see https://developer-pro.bitmart.com/en/spot/#get-currency-list-v1
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an associative dictionary of currencies
     */
    public java.util.concurrent.CompletableFuture<Object> fetchCurrencies(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.publicGetAccountV1Currencies(parameters)).join();
            //
            //     {
            //         "message": "OK",
            //         "code": 1000,
            //         "trace": "619294ecef584282b26a3be322b1e01f.66.17403093228242229",
            //         "data": {
            //             "currencies": [
            //                 {
            //                     "currency": "BTC",
            //                     "name": "Bitcoin",
            //                     "recharge_minsize": '0.00000001',
            //                     "contract_address": null,
            //                     "network": "BTC",
            //                     "withdraw_enabled": true,
            //                     "deposit_enabled": true,
            //                     "withdraw_minsize": "0.0003",
            //                     "withdraw_minfee": "9.61",
            //                     "withdraw_fee_estimate": "9.61",
            //                     "withdraw_fee": "0.0001"
            //                 }
            //             ]
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object currencies = this.safeList(data, "currencies", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(currencies)); i++)
            {
                Object currency = Helpers.GetValue(currencies, i);
                Object fullId = this.safeString(currency, "currency");
                Object currencyId = fullId;
                Object networkId = this.safeString(currency, "network");
                Object isNtf = (Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(fullId, "NFT"), 0));
                if (!Helpers.isTrue(isNtf))
                {
                    Object parts = Helpers.split(fullId, "-");
                    currencyId = this.safeString(parts, 0);
                    Object second = this.safeString(parts, 1);
                    if (Helpers.isTrue(!Helpers.isEqual(second, null)))
                    {
                        networkId = ((String)second).toUpperCase();
                    }
                }
                Object currencyCode = this.safeCurrencyCode(currencyId);
                Object entry = this.safeDict(result, currencyCode);
                if (Helpers.isTrue(Helpers.isEqual(entry, null)))
                {
                    final Object finalCurrencyId = currencyId;
                    entry = new java.util.HashMap<String, Object>() {{
                        put( "info", currency );
                        put( "id", finalCurrencyId );
                        put( "code", currencyCode );
                        put( "precision", null );
                        put( "name", BitmartCore.this.safeString(currency, "name") );
                        put( "deposit", null );
                        put( "withdraw", null );
                        put( "active", null );
                        put( "networks", new java.util.HashMap<String, Object>() {{}} );
                        put( "type", ((Helpers.isTrue(isNtf))) ? "other" : "crypto" );
                    }};
                }
                Object networkCode = this.networkIdToCode(networkId, currencyCode);
                Object withdraw = this.safeBool(currency, "withdraw_enabled");
                Object deposit = this.safeBool(currency, "deposit_enabled");
                final Object finalNetworkId = networkId;
                final Object finalWithdraw = withdraw;
                Helpers.addElementToObject(Helpers.GetValue(entry, "networks"), networkCode, new java.util.HashMap<String, Object>() {{
        put( "info", currency );
        put( "id", finalNetworkId );
        put( "code", networkCode );
        put( "withdraw", finalWithdraw );
        put( "deposit", deposit );
        put( "active", Helpers.isTrue(finalWithdraw) && Helpers.isTrue(deposit) );
        put( "fee", BitmartCore.this.safeNumber(currency, "withdraw_fee") );
        put( "limits", new java.util.HashMap<String, Object>() {{
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "min", BitmartCore.this.safeNumber(currency, "withdraw_minsize") );
                put( "max", null );
            }} );
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "min", null );
                put( "max", null );
            }} );
        }} );
    }});
                Helpers.addElementToObject(result, currencyCode, entry);
            }
            Object keys = Helpers.objectKeys(result);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
            {
                Object key = Helpers.GetValue(keys, i);
                Object currency = Helpers.GetValue(result, key);
                Helpers.addElementToObject(result, key, this.safeCurrencyStructure(currency));
            }
            return result;
        });

    }

    public Object getCurrencyIdFromCodeAndNetwork(Object currencyCode, Object networkCode)
    {
        if (Helpers.isTrue(Helpers.isEqual(networkCode, null)))
        {
            networkCode = this.defaultNetworkCode(currencyCode); // use default network code if not provided
        }
        Object currency = this.currency(currencyCode);
        Object id = Helpers.GetValue(currency, "id");
        Object idFromNetwork = null;
        Object networks = this.safeDict(currency, "networks", new java.util.HashMap<String, Object>() {{}});
        Object networkInfo = new java.util.HashMap<String, Object>() {{}};
        if (Helpers.isTrue(Helpers.isEqual(networkCode, null)))
        {
            // network code is not provided and there is no default network code
            Object network = this.safeDict(networks, currencyCode); // trying to find network that has the same code as currency
            if (Helpers.isTrue(Helpers.isEqual(network, null)))
            {
                // use the first network in the networks list if there is no network code with the same code as currency
                Object keys = Helpers.objectKeys(networks);
                Object length = Helpers.getArrayLength(keys);
                if (Helpers.isTrue(Helpers.isGreaterThan(length, 0)))
                {
                    network = this.safeValue(networks, Helpers.GetValue(keys, 0));
                }
            }
            networkInfo = this.safeDict(network, "info", new java.util.HashMap<String, Object>() {{}});
            idFromNetwork = this.safeString(networkInfo, "currency"); // use currency name from network
        } else
        {
            Object providedOrDefaultNetwork = this.safeDict(networks, networkCode);
            if (Helpers.isTrue(!Helpers.isEqual(providedOrDefaultNetwork, null)))
            {
                networkInfo = this.safeDict(providedOrDefaultNetwork, "info", new java.util.HashMap<String, Object>() {{}});
                idFromNetwork = this.safeString(networkInfo, "currency"); // use currency name from network
            } else
            {
                id = Helpers.add(id, Helpers.add("-", this.networkCodeToId(networkCode, currencyCode))); // use concatenated currency id and network code if network is not found
            }
        }
        return ((Helpers.isTrue((!Helpers.isEqual(idFromNetwork, null))))) ? idFromNetwork : id;
    }

