    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // spot (REST) fetchTickers
        //
        //     {
        //         'result': [
        //             "AFIN_USDT",     // symbol
        //             "0.001047",      // last
        //             "11110",         // v_24h
        //             "11.632170",     // qv_24h
        //             "0.001048",      // open_24h
        //             "0.001048",      // high_24h
        //             "0.001047",      // low_24h
        //             "-0.00095",      // price_change_24h
        //             "0.001029",      // bid_px
        //             "5555",          // bid_sz
        //             "0.001041",      // ask_px
        //             "5297",          // ask_sz
        //             "1717122550482"  // timestamp
        //         ]
        //     }
        //
        // spot (REST) fetchTicker
        //
        //     {
        //         "symbol": "BTC_USDT",
        //         "last": "68500.00",
        //         "v_24h": "10491.65490",
        //         "qv_24h": "717178990.42",
        //         "open_24h": "68149.75",
        //         "high_24h": "69499.99",
        //         "low_24h": "67132.40",
        //         "fluctuation": "0.00514",
        //         "bid_px": "68500",
        //         "bid_sz": "0.00162",
        //         "ask_px": "68500.01",
        //         "ask_sz": "0.01722",
        //         "ts": "1717131391671"
        //     }
        //
        // spot (WS)
        //
        //      {
        //          "symbol":"BTC_USDT",
        //          "last_price":"146.24",
        //          "open_24h":"147.17",
        //          "high_24h":"147.48",
        //          "low_24h":"143.88",
        //          "base_volume_24h":"117387.58", // NOT base, but quote currency!!!
        //          "s_t": 1610936002
        //      }
        //
        // swap
        //
        //     {
        //         "symbol": "BTCUSDT",
        //         "product_type": 1,
        //         "open_timestamp": 1645977600000,
        //         "expire_timestamp": 0,
        //         "settle_timestamp": 0,
        //         "base_currency": "BTC",
        //         "quote_currency": "USDT",
        //         "last_price": "63547.4",
        //         "volume_24h": "110938430",
        //         "turnover_24h": "7004836342.6944",
        //         "index_price": "63587.85404255",
        //         "index_name": "BTCUSDT",
        //         "contract_size": "0.001",
        //         "min_leverage": "1",
        //         "max_leverage": "100",
        //         "price_precision": "0.1",
        //         "vol_precision": "1",
        //         "max_volume": "1000000",
        //         "min_volume": "1",
        //         "funding_rate": "0.0000801",
        //         "expected_funding_rate": "-0.0000035",
        //         "open_interest": "278214",
        //         "open_interest_value": "17555316.9355496",
        //         "high_24h": "64109.4",
        //         "low_24h": "61857.6",
        //         "change_24h": "0.0239264900886327",
        //         "funding_time": 1726819200000
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object result = this.safeList(ticker, "result", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object average = this.safeString2(ticker, "avg_price", "index_price");
        Object marketId = this.safeString2(ticker, "symbol", "contract_symbol");
        Object timestamp = this.safeInteger2(ticker, "timestamp", "ts");
        Object last = this.safeString2(ticker, "last_price", "last");
        Object percentage = this.safeString2(ticker, "price_change_percent_24h", "change_24h");
        Object change = this.safeString(ticker, "fluctuation");
        Object high = this.safeString2(ticker, "high_24h", "high_price");
        Object low = this.safeString2(ticker, "low_24h", "low_price");
        Object bid = this.safeString2(ticker, "best_bid", "bid_px");
        Object bidVolume = this.safeString2(ticker, "best_bid_size", "bid_sz");
        Object ask = this.safeString2(ticker, "best_ask", "ask_px");
        Object askVolume = this.safeString2(ticker, "best_ask_size", "ask_sz");
        Object open = this.safeString(ticker, "open_24h");
        Object baseVolume = this.safeStringN(ticker, new java.util.ArrayList<Object>(java.util.Arrays.asList("base_volume_24h", "v_24h", "volume_24h")));
        Object quoteVolume = this.safeStringLowerN(ticker, new java.util.ArrayList<Object>(java.util.Arrays.asList("quote_volume_24h", "qv_24h", "turnover_24h")));
        Object listMarketId = this.safeString(result, 0);
        if (Helpers.isTrue(!Helpers.isEqual(listMarketId, null)))
        {
            marketId = listMarketId;
            timestamp = this.safeInteger(result, 12);
            high = this.safeString(result, 5);
            low = this.safeString(result, 6);
            bid = this.safeString(result, 8);
            bidVolume = this.safeString(result, 9);
            ask = this.safeString(result, 10);
            askVolume = this.safeString(result, 11);
            open = this.safeString(result, 4);
            last = this.safeString(result, 1);
            change = this.safeString(result, 7);
            baseVolume = this.safeString(result, 2);
            quoteVolume = this.safeStringLower(result, 3);
        }
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        if (Helpers.isTrue(Helpers.isEqual(timestamp, null)))
        {
            // ticker from WS has a different field (in seconds)
            timestamp = this.safeIntegerProduct(ticker, "s_t", 1000);
        }
        if (Helpers.isTrue(Helpers.isEqual(percentage, null)))
        {
            percentage = Precise.stringMul(change, "100");
        }
        if (Helpers.isTrue(Helpers.isEqual(quoteVolume, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(baseVolume, null)))
            {
                // this is swap
                quoteVolume = this.safeString(ticker, "volume_24h", quoteVolume);
            } else
            {
                // this is a ticker from websockets
                // contrary to name and documentation, base_volume_24h is actually the quote volume
                quoteVolume = baseVolume;
                baseVolume = null;
            }
        }
        final Object finalTimestamp = timestamp;
        final Object finalHigh = high;
        final Object finalLow = low;
        final Object finalBid = bid;
        final Object finalBidVolume = bidVolume;
        final Object finalAsk = ask;
        final Object finalAskVolume = askVolume;
        final Object finalOpen = open;
        final Object finalLast = last;
        final Object finalPercentage = percentage;
        final Object finalBaseVolume = baseVolume;
        final Object finalQuoteVolume = quoteVolume;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", finalTimestamp );
            put( "datetime", BitmartCore.this.iso8601(finalTimestamp) );
            put( "high", finalHigh );
            put( "low", finalLow );
            put( "bid", finalBid );
            put( "bidVolume", finalBidVolume );
            put( "ask", finalAsk );
            put( "askVolume", finalAskVolume );
            put( "vwap", null );
            put( "open", finalOpen );
            put( "close", finalLast );
            put( "last", finalLast );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", finalPercentage );
            put( "average", average );
            put( "baseVolume", finalBaseVolume );
            put( "quoteVolume", finalQuoteVolume );
            put( "indexPrice", BitmartCore.this.safeString(ticker, "index_price") );
            put( "info", ticker );
        }}, market);
    }

    /**
     * @method
     * @name bitmart#fetchTicker
     * @description fetches a price ticker, a statistical calculation with the information calculated over the past 24 hours for a specific market
     * @see https://developer-pro.bitmart.com/en/spot/#get-ticker-of-a-trading-pair-v3
     * @see https://developer-pro.bitmart.com/en/futuresv2/#get-contract-details
     * @param {string} symbol unified symbol of the market to fetch the ticker for
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [ticker structure]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTicker(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object response = null;
            if (Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
                response = (this.publicGetContractPublicDetails(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
                response = (this.publicGetSpotQuotationV3Ticker(this.extend(request, parameters))).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(this.id, " fetchTicker() does not support "), Helpers.GetValue(market, "type")), " markets, only spot and swap markets are accepted")) ;
            }
            // fails in naming for contract tickers 'contract_symbol'
            Object tickers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object ticker = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
            {
                ticker = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            } else
            {
                Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
                tickers = this.safeList(data, "symbols", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                ticker = this.safeDict(tickers, 0, new java.util.HashMap<String, Object>() {{}});
            }
            return this.parseTicker(ticker, market);
        });

    }

    /**
     * @method
     * @name bitmart#fetchTickers
     * @description fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for each market
     * @see https://developer-pro.bitmart.com/en/spot/#get-ticker-of-all-pairs-v3
     * @see https://developer-pro.bitmart.com/en/futuresv2/#get-contract-details
     * @param {string[]|undefined} symbols unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            symbols = this.marketSymbols(symbols);
            Object type = null;
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                Object symbol = this.safeString(symbols, 0);
                market = this.market(symbol);
            }
            var typeparametersVariable = this.handleMarketTypeAndParams("fetchTickers", market, parameters);
            type = ((java.util.List<Object>) typeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
            Object response = null;
            if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
            {
                response = (this.publicGetSpotQuotationV3Tickers(parameters)).join();
            } else if (Helpers.isTrue(Helpers.isEqual(type, "swap")))
            {
                response = (this.publicGetContractPublicDetails(parameters)).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(this.id, " fetchTickers() does not support "), type), " markets, only spot and swap markets are accepted")) ;
            }
            Object tickers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
            {
                tickers = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            } else
            {
                Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
                tickers = this.safeList(data, "symbols", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            }
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(tickers)); i++)
            {
                Object ticker = new java.util.HashMap<String, Object>() {{}};
                if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
                {
                    final Object finalTickers = tickers;
                    final Object finalI = i;
                    ticker = this.parseTicker(new java.util.HashMap<String, Object>() {{
                        put( "result", Helpers.GetValue(finalTickers, finalI) );
                    }});
                } else
                {
                    ticker = this.parseTicker(Helpers.GetValue(tickers, i));
                }
                Object symbol = Helpers.GetValue(ticker, "symbol");
                Helpers.addElementToObject(result, symbol, ticker);
            }
            return this.filterByArrayTickers(result, "symbol", symbols);
        });

    }

