    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // public fetchTrades spot ( amount = count * price )
        //
        //     [
        //         "BTC_USDT",      // symbol
        //         "1717212457302", // timestamp
        //         "67643.11",      // price
        //         "0.00106",       // size
        //         "sell"           // side
        //     ]
        //
        // spot: fetchMyTrades
        //
        //    {
        //        "tradeId":"182342999769370687",
        //        "orderId":"183270218784142990",
        //        "clientOrderId":"183270218784142990",
        //        "symbol":"ADA_USDT",
        //        "side":"buy",
        //        "orderMode":"spot",
        //        "type":"market",
        //        "price":"0.245948",
        //        "size":"20.71",
        //        "notional":"5.09358308",
        //        "fee":"0.00509358",
        //        "feeCoinName":"USDT",
        //        "tradeRole":"taker",
        //        "createTime":1695658457836,
        //    }
        //
        // swap: fetchMyTrades
        //
        //    {
        //        "order_id": "230930336848609",
        //        "trade_id": "6212604014",
        //        "symbol": "BTCUSDT",
        //        "side": 3,
        //        "price": "26910.4",
        //        "vol": "1",
        //        "exec_type": "Taker",
        //        "profit": false,
        //        "create_time": 1695961596692,
        //        "realised_profit": "-0.0003",
        //        "paid_fees": "0.01614624"
        //    }
        //
        // ws swap
        //
        //    {
        //        'fee': '-0.000044502',
        //        'feeCcy': 'USDT',
        //        'fillPrice': '74.17',
        //        'fillQty': '1',
        //        'lastTradeID': 6802340762
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeIntegerN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("createTime", "create_time", 1)));
        Object isPublic = this.safeString(trade, 0);
        Object isPublicTrade = (!Helpers.isEqual(isPublic, null));
        Object amount = null;
        Object cost = null;
        Object type = null;
        Object side = null;
        if (Helpers.isTrue(isPublicTrade))
        {
            amount = this.safeString2(trade, "count", 3);
            cost = this.safeString(trade, "amount");
            side = this.safeString2(trade, "type", 4);
        } else
        {
            amount = this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("size", "vol", "fillQty")));
            cost = this.safeString(trade, "notional");
            type = this.safeString(trade, "type");
            side = this.parseOrderSide(this.safeString(trade, "side"));
        }
        Object marketId = this.safeString2(trade, "symbol", 0);
        market = this.safeMarket(marketId, market);
        Object feeCostString = this.safeString2(trade, "fee", "paid_fees");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "feeCoinName");
            Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
            if (Helpers.isTrue(Helpers.isEqual(feeCurrencyCode, null)))
            {
                feeCurrencyCode = ((Helpers.isTrue((Helpers.isEqual(side, "buy"))))) ? Helpers.GetValue(market, "base") : Helpers.GetValue(market, "quote");
            }
            final Object finalFeeCostString = feeCostString;
            final Object finalFeeCurrencyCode = feeCurrencyCode;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", finalFeeCurrencyCode );
            }};
        }
        final Object finalMarket = market;
        final Object finalType = type;
        final Object finalSide = side;
        final Object finalAmount = amount;
        final Object finalCost = cost;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", BitmartCore.this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("tradeId", "trade_id", "lastTradeID"))) );
            put( "order", BitmartCore.this.safeString2(trade, "orderId", "order_id") );
            put( "timestamp", timestamp );
            put( "datetime", BitmartCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", finalType );
            put( "side", finalSide );
            put( "price", BitmartCore.this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("price", "fillPrice", 2))) );
            put( "amount", finalAmount );
            put( "cost", finalCost );
            put( "takerOrMaker", BitmartCore.this.safeStringLower2(trade, "tradeRole", "exec_type") );
            put( "fee", finalFee );
        }}, market);
    }

