            {
                market = this.market(symbol);
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
            }
            Object type = null;
            Object response = null;
            var typeparametersVariable = this.handleMarketTypeAndParams("fetchMyTrades", market, parameters);
            type = ((java.util.List<Object>) typeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
            Object until = this.safeIntegerN(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("until", "endTime", "end_time")));
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("until")));
            if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
            {
                Object marginMode = null;
                var marginModeparametersVariable = this.handleMarginModeAndParams("fetchMyTrades", parameters);
                marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
                parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
                if (Helpers.isTrue(Helpers.isEqual(marginMode, "isolated")))
                {
                    Helpers.addElementToObject(request, "orderMode", "iso_margin");
                }
                Object options = this.safeDict(this.options, "fetchMyTrades", new java.util.HashMap<String, Object>() {{}});
                Object maxLimit = 200;
                Object defaultLimit = this.safeInteger(options, "limit", maxLimit);
                if (Helpers.isTrue(Helpers.isEqual(limit, null)))
                {
                    limit = defaultLimit;
                }
                Helpers.addElementToObject(request, "limit", Helpers.mathMin(limit, maxLimit));
                if (Helpers.isTrue(!Helpers.isEqual(since, null)))
                {
                    Helpers.addElementToObject(request, "startTime", since);
                }
                if (Helpers.isTrue(!Helpers.isEqual(until, null)))
                {
                    Helpers.addElementToObject(request, "endTime", until);
                }
                response = (this.privatePostSpotV4QueryTrades(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isEqual(type, "swap")))
            {
                if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchMyTrades() requires a symbol argument")) ;
                }
                if (Helpers.isTrue(!Helpers.isEqual(since, null)))
                {
                    Helpers.addElementToObject(request, "start_time", since);
                }
                if (Helpers.isTrue(!Helpers.isEqual(until, null)))
                {
                    Helpers.addElementToObject(request, "end_time", until);
                }
                response = (this.privateGetContractPrivateTrades(this.extend(request, parameters))).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(this.id, " fetchMyTrades() does not support "), type), " orders, only spot and swap orders are accepted")) ;
            }
            //
            // spot
            //
            //    {
            //        "code":1000,
            //        "message":"success",
            //        "data":[
            //           {
            //              "tradeId":"182342999769370687",
