    public Object customParseBalance(Object response, Object marketType)
    {
        Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
        Object wallet = null;
        if (Helpers.isTrue(Helpers.isEqual(marketType, "swap")))
        {
            wallet = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        } else if (Helpers.isTrue(Helpers.isEqual(marketType, "margin")))
        {
            wallet = this.safeList(data, "symbols", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        } else
        {
            wallet = this.safeList(data, "wallet", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        }
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
        }};
        if (Helpers.isTrue(Helpers.isEqual(marketType, "margin")))
        {
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(wallet)); i++)
            {
                Object entry = Helpers.GetValue(wallet, i);
                Object marketId = this.safeString(entry, "symbol");
                Object symbol = this.safeSymbol(marketId, null, "_");
                Object base = this.safeDict(entry, "base", new java.util.HashMap<String, Object>() {{}});
                Object quote = this.safeDict(entry, "quote", new java.util.HashMap<String, Object>() {{}});
                Object baseCode = this.safeCurrencyCode(this.safeString(base, "currency"));
                Object quoteCode = this.safeCurrencyCode(this.safeString(quote, "currency"));
                Object subResult = new java.util.HashMap<String, Object>() {{}};
                Helpers.addElementToObject(subResult, baseCode, this.parseBalanceHelper(base));
                Helpers.addElementToObject(subResult, quoteCode, this.parseBalanceHelper(quote));
                Helpers.addElementToObject(result, symbol, this.safeBalance(subResult));
            }
            return result;
        } else
        {
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(wallet)); i++)
            {
                Object balance = Helpers.GetValue(wallet, i);
                Object currencyId = this.safeString2(balance, "id", "currency");
                currencyId = this.safeString(balance, "coin_code", currencyId);
                Object code = this.safeCurrencyCode(currencyId);
                Object account = this.account();
                Helpers.addElementToObject(account, "free", this.safeString2(balance, "available", "available_balance"));
                Helpers.addElementToObject(account, "used", this.safeStringN(balance, new java.util.ArrayList<Object>(java.util.Arrays.asList("unAvailable", "frozen", "frozen_balance"))));
                Helpers.addElementToObject(result, code, account);
            }
            return this.safeBalance(result);
        }
    }

    public Object parseBalanceHelper(Object entry)
    {
        Object account = this.account();
        Helpers.addElementToObject(account, "used", this.safeString(entry, "frozen"));
        Helpers.addElementToObject(account, "free", this.safeString(entry, "available"));
        Helpers.addElementToObject(account, "total", this.safeString(entry, "total_asset"));
        Object debt = this.safeString(entry, "borrow_unpaid");
        Object interest = this.safeString(entry, "interest_unpaid");
        Helpers.addElementToObject(account, "debt", Precise.stringAdd(debt, interest));
        return account;
    }

