    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder, editOrder
        //
        //     {
        //         "order_id": 2707217580
        //     }
        //
        // swap
        //   "data": {
        //       "order_id": 231116359426639,
        //       "price": "market price"
        //    },
        //
        // cancelOrder
        //
        //     "2707217580" // order id
        //
        // spot fetchOrder, fetchOrdersByStatus, fetchOpenOrders, fetchClosedOrders
        //
        //     {
        //         "order_id":1736871726781,
        //         "symbol":"BTC_USDT",
        //         "create_time":1591096004000,
        //         "side":"sell",
        //         "type":"market", // limit, market, limit_maker, ioc
        //         "price":"0.00",
        //         "price_avg":"0.00",
        //         "size":"0.02000",
        //         "notional":"0.00000000",
        //         "filled_notional":"0.00000000",
        //         "filled_size":"0.00000",
        //         "status":"8"
        //     }
        //
        // spot v4
        //    {
        //        "orderId" : "118100034543076010",
        //        "clientOrderId" : "118100034543076010",
        //        "symbol" : "BTC_USDT",
        //        "side" : "buy",
        //        "orderMode" : "spot",
        //        "type" : "limit",
        //        "state" : "filled",
        //        "price" : "48800.00",
        //        "priceAvg" : "39999.00",
        //        "size" : "0.10000",
        //        "filledSize" : "0.10000",
        //        "notional" : "4880.00000000",
        //        "filledNotional" : "3999.90000000",
        //        "createTime" : 1681701557927,
        //        "updateTime" : 1681701559408
        //    }
        //
        // swap: fetchOrder, fetchOpenOrders, fetchClosedOrders
        //
        //     {
        //         "order_id": "230935812485489",
        //         "client_order_id": "",
        //         "price": "24000",
        //         "size": "1",
        //         "symbol": "BTCUSDT",
        //         "state": 2,
        //         "side": 1,
        //         "type": "limit",
        //         "leverage": "10",
        //         "open_type": "isolated",
        //         "deal_avg_price": "0",
        //         "deal_size": "0",
        //         "create_time": 1695702258629,
        //         "update_time": 1695702258642,
        //         "activation_price_type": 0,
        //         "activation_price": "",
        //         "callback_rate": ""
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = null;
        if (Helpers.isTrue((order instanceof String)))
        {
            id = order;
            order = new java.util.HashMap<String, Object>() {{}};
        }
        id = this.safeString2(order, "order_id", "orderId", id);
        Object timestamp = this.safeInteger2(order, "create_time", "createTime");
        Object marketId = this.safeString(order, "symbol");
        Object symbol = this.safeSymbol(marketId, market);
        market = this.safeMarket(symbol, market);
        Object orderType = this.safeString(market, "type", "spot");
        Object type = this.safeString(order, "type");
        Object timeInForce = null;
        Object postOnly = null;
        if (Helpers.isTrue(Helpers.isEqual(type, "limit_maker")))
        {
            type = "limit";
            postOnly = true;
            timeInForce = "PO";
        }
        if (Helpers.isTrue(Helpers.isEqual(type, "ioc")))
        {
            type = "limit";
            timeInForce = "IOC";
        }
        Object priceString = this.safeString(order, "price");
        if (Helpers.isTrue(Helpers.isEqual(priceString, "market price")))
        {
            priceString = null;
        }
        Object trailingActivationPrice = this.safeNumber(order, "activation_price");
        final Object finalId = id;
        final Object finalOrder = order;
        final Object finalType = type;
        final Object finalTimeInForce = timeInForce;
        final Object finalPostOnly = postOnly;
        final Object finalPriceString = priceString;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", finalId );
            put( "clientOrderId", BitmartCore.this.safeString2(finalOrder, "client_order_id", "clientOrderId") );
            put( "info", finalOrder );
            put( "timestamp", timestamp );
            put( "datetime", BitmartCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", BitmartCore.this.safeInteger(finalOrder, "update_time") );
            put( "symbol", symbol );
            put( "type", finalType );
            put( "timeInForce", finalTimeInForce );
            put( "postOnly", finalPostOnly );
            put( "side", BitmartCore.this.parseOrderSide(BitmartCore.this.safeString(finalOrder, "side")) );
            put( "price", BitmartCore.this.omitZero(finalPriceString) );
            put( "triggerPrice", trailingActivationPrice );
            put( "amount", BitmartCore.this.omitZero(BitmartCore.this.safeString(finalOrder, "size")) );
            put( "cost", BitmartCore.this.safeString2(finalOrder, "filled_notional", "filledNotional") );
            put( "average", BitmartCore.this.safeStringN(finalOrder, new java.util.ArrayList<Object>(java.util.Arrays.asList("price_avg", "priceAvg", "deal_avg_price"))) );
            put( "filled", BitmartCore.this.safeStringN(finalOrder, new java.util.ArrayList<Object>(java.util.Arrays.asList("filled_size", "filledSize", "deal_size"))) );
            put( "remaining", null );
            put( "status", BitmartCore.this.parseOrderStatusByType(orderType, BitmartCore.this.safeString2(finalOrder, "status", "state")) );
            put( "fee", null );
            put( "trades", null );
        }}, market);
    }

