    public Object parseDepositAddress(Object depositAddress, Object... optionalArgs)
    {
        //
        // fetchDepositAddress
        //    {
        //        currency: 'ETH',
        //        chain: 'Ethereum',
        //        address: '0x99B5EEc2C520f86F0F62F05820d28D05D36EccCf',
        //        address_memo: ''
        //    }
        //
        // fetchWithdrawAddress
        //     {
        //         "currency": "ETH",
        //         "network": "ETH",
        //         "address": "0x1121",
        //         "memo": "12",
        //         "remark": "12",
        //         "addressType": 0,
        //         "verifyStatus": 0
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(depositAddress, "currency");
        Object network = this.safeString2(depositAddress, "chain", "network");
        if (Helpers.isTrue(Helpers.isLessThan(Helpers.getIndexOf(currencyId, "NFT"), 0)))
        {
            Object parts = Helpers.split(currencyId, "-");
            currencyId = this.safeString(parts, 0);
            Object secondPart = this.safeString(parts, 1);
            if (Helpers.isTrue(!Helpers.isEqual(secondPart, null)))
            {
                network = secondPart;
            }
        }
        Object address = this.safeString(depositAddress, "address");
        currency = this.safeCurrency(currencyId, currency);
        Object code = this.safeString(currency, "code");
        this.checkAddress(address);
        final Object finalNetwork = network;
        return new java.util.HashMap<String, Object>() {{
            put( "info", depositAddress );
            put( "currency", code );
            put( "network", BitmartCore.this.networkIdToCode(finalNetwork, code) );
            put( "address", address );
            put( "tag", BitmartCore.this.safeString2(depositAddress, "address_memo", "memo") );
        }};
    }

    /**
     * @method
     * @name bitmart#withdraw
     * @description make a withdrawal
     * @see https://developer-pro.bitmart.com/en/spot/#withdraw-signed
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.network] the network name for this withdrawal
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            var tagparametersVariable = this.handleWithdrawTagAndParams(tag, parameters);
            tag = ((java.util.List<Object>) tagparametersVariable).get(0);
            parameters = ((java.util.List<Object>) tagparametersVariable).get(1);
            this.checkAddress(address);
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object network = null;
            var networkparametersVariable = this.handleNetworkCodeAndParams(parameters);
            network = ((java.util.List<Object>) networkparametersVariable).get(0);
            parameters = ((java.util.List<Object>) networkparametersVariable).get(1);
            final Object finalNetwork = network;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "currency", BitmartCore.this.getCurrencyIdFromCodeAndNetwork(code, finalNetwork) );
                put( "amount", amount );
                put( "destination", "To Digital Address" );
                put( "address", address );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(tag, null)))
            {
                Helpers.addElementToObject(request, "address_memo", tag);
            }
            Object response = (this.privatePostAccountV1WithdrawApply(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": 1000,
            //         "trace":"886fb6ae-456b-4654-b4e0-d681ac05cea1",
            //         "message": "OK",
            //         "data": {
            //             "withdraw_id": "121212"
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object transaction = this.parseTransaction(data, currency);
            final Object finalTag = tag;
            return this.extend(transaction, new java.util.HashMap<String, Object>() {{
                put( "code", code );
                put( "address", address );
                put( "tag", finalTag );
            }});
        });

    }

