    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "0", "pending" );
            put( "1", "pending" );
            put( "2", "pending" );
            put( "3", "ok" );
            put( "4", "canceled" );
            put( "5", "failed" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // withdraw
        //
        //     {
        //         "withdraw_id": "121212"
        //     }
        //
        // fetchDeposits, fetchWithdrawals, fetchWithdrawal
        //
        //     {
        //         "withdraw_id":"1679952",
        //         "deposit_id":"",
        //         "operation_type":"withdraw",
        //         "currency":"BMX",
        //         "apply_time":1588867374000,
        //         "arrival_amount":"59.000000000000",
        //         "fee":"1.000000000000",
        //         "status":0,
        //         "address":"0xe57b69a8776b37860407965B73cdFFBDFe668Bb5",
        //         "address_memo":"",
        //         "tx_id":""
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object id = null;
        Object withdrawId = this.safeString(transaction, "withdraw_id");
        Object depositId = this.safeString(transaction, "deposit_id");
        Object type = null;
        if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(withdrawId, null))) && Helpers.isTrue((!Helpers.isEqual(withdrawId, "")))))
        {
            type = "withdraw";
            id = withdrawId;
        } else if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(depositId, null))) && Helpers.isTrue((!Helpers.isEqual(depositId, "")))))
        {
            type = "deposit";
            id = depositId;
        }
        Object amount = this.safeNumber(transaction, "arrival_amount");
        Object timestamp = this.safeInteger(transaction, "apply_time");
        Object currencyId = this.safeString(transaction, "currency");
        Object networkId = null;
        if (Helpers.isTrue(!Helpers.isEqual(currencyId, null)))
        {
            if (Helpers.isTrue(Helpers.isLessThan(Helpers.getIndexOf(currencyId, "NFT"), 0)))
            {
                Object parts = Helpers.split(currencyId, "-");
                currencyId = this.safeString(parts, 0);
                networkId = this.safeString(parts, 1);
            }
        }
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object status = this.parseTransactionStatus(this.safeString(transaction, "status"));
        Object feeCost = this.safeNumber(transaction, "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", code );
            }};
        }
        Object txid = this.safeString(transaction, "tx_id");
        Object address = this.safeString(transaction, "address");
        Object tag = this.safeString(transaction, "address_memo");
        final Object finalId = id;
        final Object finalNetworkId = networkId;
        final Object finalType = type;
        final Object finalTimestamp = timestamp;
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", finalId );
            put( "currency", code );
            put( "amount", amount );
            put( "network", BitmartCore.this.networkIdToCode(finalNetworkId, code) );
            put( "address", address );
            put( "addressFrom", null );
            put( "addressTo", null );
            put( "tag", tag );
            put( "tagFrom", null );
            put( "tagTo", null );
            put( "status", status );
            put( "type", finalType );
            put( "updated", null );
            put( "txid", txid );
            put( "internal", null );
            put( "comment", null );
            put( "timestamp", ((Helpers.isTrue((!Helpers.isEqual(finalTimestamp, 0))))) ? finalTimestamp : null );
            put( "datetime", ((Helpers.isTrue((!Helpers.isEqual(finalTimestamp, 0))))) ? BitmartCore.this.iso8601(finalTimestamp) : null );
            put( "fee", finalFee );
        }};
    }

