        return new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "base", BitmartCore.this.safeCurrencyCode(baseId) );
            put( "baseRate", BitmartCore.this.safeNumber(baseData, "hourly_interest") );
            put( "quote", BitmartCore.this.safeCurrencyCode(quoteId) );
            put( "quoteRate", BitmartCore.this.safeNumber(quoteData, "hourly_interest") );
            put( "period", 3600000 );
            put( "timestamp", null );
            put( "datetime", null );
            put( "info", info );
        }};
