    /**
     * @method
     * @name bitmart#transfer
     * @description transfer currency internally between wallets on the same account, currently only supports transfer between spot and margin
     * @see https://developer-pro.bitmart.com/en/spot/#margin-asset-transfer-signed
     * @see https://developer-pro.bitmart.com/en/futuresv2/#transfer-signed
     * @param {string} code unified currency code
     * @param {float} amount amount to transfer
     * @param {string} fromAccount account to transfer from
     * @param {string} toAccount account to transfer to
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transfer structure]{@link https://docs.ccxt.com/?id=transfer-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> transfer(Object code, Object amount, Object fromAccount2, Object toAccount2, Object... optionalArgs)
    {
        final Object fromAccount3 = fromAccount2;
        final Object toAccount3 = toAccount2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object fromAccount = fromAccount3;
            Object toAccount = toAccount3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object amountToPrecision = this.currencyToPrecision(code, amount);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "amount", amountToPrecision );
                put( "currency", Helpers.GetValue(currency, "id") );
            }};
            Object fromId = this.convertTypeToAccount(fromAccount);
            Object toId = this.convertTypeToAccount(toAccount);
            if (Helpers.isTrue(Helpers.isEqual(fromAccount, "spot")))
            {
                if (Helpers.isTrue(Helpers.isEqual(toAccount, "margin")))
                {
                    Helpers.addElementToObject(request, "side", "in");
                    Helpers.addElementToObject(request, "symbol", toId);
                } else if (Helpers.isTrue(Helpers.isEqual(toAccount, "swap")))
                {
                    Helpers.addElementToObject(request, "type", "spot_to_contract");
                }
            } else if (Helpers.isTrue(Helpers.isEqual(toAccount, "spot")))
            {
                if (Helpers.isTrue(Helpers.isEqual(fromAccount, "margin")))
                {
                    Helpers.addElementToObject(request, "side", "out");
                    Helpers.addElementToObject(request, "symbol", fromId);
                } else if (Helpers.isTrue(Helpers.isEqual(fromAccount, "swap")))
                {
                    Helpers.addElementToObject(request, "type", "contract_to_spot");
                }
            } else
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " transfer() requires either fromAccount or toAccount to be spot")) ;
            }
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(fromAccount, "margin"))) || Helpers.isTrue((Helpers.isEqual(toAccount, "margin")))))
            {
                response = (this.privatePostSpotV1MarginIsolatedTransfer(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(fromAccount, "swap"))) || Helpers.isTrue((Helpers.isEqual(toAccount, "swap")))))
            {
                response = (this.privatePostAccountV1TransferContract(this.extend(request, parameters))).join();
            }
            //
            // margin
            //
            //     {
            //         "message": "OK",
            //         "code": 1000,
            //         "trace": "b26cecec-ef5a-47d9-9531-2bd3911d3d55",
            //         "data": {
            //             "transfer_id": "ca90d97a621e47d49774f19af6b029f5"
            //         }
            //     }
            //
            // swap
            //
            //     {
            //         "message": "OK",
            //         "code": 1000,
            //         "trace": "4cad858074667097ac6ba5257c57305d.68.16953302431189455",
            //         "data": {
            //             "currency": "USDT",
            //             "amount": "5"
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            final Object finalResponse = response;
            return this.extend(this.parseTransfer(data, currency), new java.util.HashMap<String, Object>() {{
                put( "status", BitmartCore.this.parseTransferStatus(BitmartCore.this.safeString2(finalResponse, "code", "message")) );
            }});
        });

    }

