            put( "fromAccount", BitmartCore.this.parseTransferFromAccount(BitmartCore.this.safeString(transfer, "type")) );
            put( "toAccount", BitmartCore.this.parseTransferToAccount(BitmartCore.this.safeString(transfer, "type")) );
