    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol": "BTCUSDT",
        //         "leverage": "10",
        //         "timestamp": 1696392515269,
        //         "current_fee": "0.0014250028",
        //         "open_timestamp": 1696392256998,
        //         "current_value": "27.4039",
        //         "mark_price": "27.4039",
        //         "position_value": "27.4079",
        //         "position_cross": "3.75723474",
        //         "maintenance_margin": "0.1370395",
        //         "close_vol": "0",
        //         "close_avg_price": "0",
        //         "open_avg_price": "27407.9",
        //         "entry_price": "27407.9",
        //         "current_amount": "1",
        //         "unrealized_value": "-0.004",
        //         "realized_value": "-0.01644474",
        //         "position_type": 1
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeInteger(position, "timestamp");
        Object side = this.safeInteger(position, "position_type");
        Object maintenanceMargin = this.safeString(position, "maintenance_margin");
        Object notional = this.safeString(position, "current_value");
        Object collateral = this.safeString(position, "position_cross");
        Object maintenanceMarginPercentage = Precise.stringDiv(maintenanceMargin, notional);
        Object marginRatio = Precise.stringDiv(maintenanceMargin, collateral);
        final Object finalSide = side;
        final Object finalMarket = market;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", BitmartCore.this.iso8601(timestamp) );
            put( "lastUpdateTimestamp", null );
            put( "hedged", null );
            put( "side", ((Helpers.isTrue((Helpers.isEqual(finalSide, 1))))) ? "long" : "short" );
            put( "contracts", BitmartCore.this.safeNumber(position, "current_amount") );
            put( "contractSize", BitmartCore.this.safeNumber(finalMarket, "contractSize") );
            put( "entryPrice", BitmartCore.this.safeNumber(position, "entry_price") );
            put( "markPrice", BitmartCore.this.safeNumber(position, "mark_price") );
            put( "lastPrice", null );
            put( "notional", BitmartCore.this.parseNumber(notional) );
            put( "leverage", BitmartCore.this.safeNumber(position, "leverage") );
            put( "collateral", BitmartCore.this.parseNumber(collateral) );
            put( "initialMargin", null );
            put( "initialMarginPercentage", null );
            put( "maintenanceMargin", BitmartCore.this.parseNumber(maintenanceMargin) );
            put( "maintenanceMarginPercentage", BitmartCore.this.parseNumber(maintenanceMarginPercentage) );
            put( "unrealizedPnl", BitmartCore.this.safeNumber(position, "unrealized_value") );
            put( "realizedPnl", BitmartCore.this.safeNumber(position, "realized_value") );
            put( "liquidationPrice", null );
            put( "marginMode", null );
            put( "percentage", null );
            put( "marginRatio", BitmartCore.this.parseNumber(marginRatio) );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
        }});
    }

    /**
     * @method
     * @name bitmart#fetchMyLiquidations
     * @description retrieves the users liquidated positions
     * @see https://developer-pro.bitmart.com/en/futuresv2/#get-order-history-keyed
     * @param {string} symbol unified CCXT market symbol
     * @param {int} [since] the earliest time in ms to fetch liquidations for
     * @param {int} [limit] the maximum number of liquidation structures to retrieve
     * @param {object} [params] exchange specific parameters for the bitmart api endpoint
     * @param {int} [params.until] timestamp in ms of the latest liquidation
     * @returns {object} an array of [liquidation structures]{@link https://docs.ccxt.com/?id=liquidation-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyLiquidations(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchMyLiquidations() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            if (!Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                throw new NotSupported((String)Helpers.add(this.id, " fetchMyLiquidations() supports swap markets only")) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "start_time", since);
            }
            var requestparametersVariable = this.handleUntilOption("end_time", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            Object response = (this.privateGetContractPrivateOrderHistory(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": 1000,
            //         "message": "Ok",
            //         "data": [
            //             {
            //                 "order_id": "231007865458273",
            //                 "client_order_id": "",
            //                 "price": "27407.9",
            //                 "size": "1",
            //                 "symbol": "BTCUSDT",
            //                 "state": 4,
            //                 "side": 3,
            //                 "type": "liquidate",
            //                 "leverage": "10",
            //                 "open_type": "isolated",
            //                 "deal_avg_price": "27422.6",
            //                 "deal_size": "1",
            //                 "create_time": 1696405864011,
            //                 "update_time": 1696405864045
            //             },
            //         ],
            //         "trace": "4cad855074664097ac6ba4257c47305d.71.16965658195443021"
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object entry = Helpers.GetValue(data, i);
                Object checkLiquidation = this.safeString(entry, "type");
                if (Helpers.isTrue(Helpers.isEqual(checkLiquidation, "liquidate")))
                {
                    ((java.util.List<Object>)result).add(entry);
                }
            }
            return this.parseLiquidations(result, market, since, limit);
        });

    }

    public Object parseLiquidation(Object liquidation, Object... optionalArgs)
    {
        //
        //     {
        //         "order_id": "231007865458273",
        //         "client_order_id": "",
        //         "price": "27407.9",
        //         "size": "1",
        //         "symbol": "BTCUSDT",
        //         "state": 4,
        //         "side": 3,
        //         "type": "market",
        //         "leverage": "10",
        //         "open_type": "isolated",
        //         "deal_avg_price": "27422.6",
        //         "deal_size": "1",
        //         "create_time": 1696405864011,
        //         "update_time": 1696405864045
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(liquidation, "symbol");
        Object timestamp = this.safeInteger(liquidation, "update_time");
        Object contractsString = this.safeString(liquidation, "deal_size");
        Object contractSizeString = this.safeString(market, "contractSize");
        Object priceString = this.safeString(liquidation, "deal_avg_price");
        Object baseValueString = Precise.stringMul(contractsString, contractSizeString);
        Object quoteValueString = Precise.stringMul(baseValueString, priceString);
        return this.safeLiquidation(new java.util.HashMap<String, Object>() {{
            put( "info", liquidation );
            put( "symbol", BitmartCore.this.safeSymbol(marketId, market) );
            put( "contracts", BitmartCore.this.parseNumber(contractsString) );
            put( "contractSize", BitmartCore.this.parseNumber(contractSizeString) );
            put( "price", BitmartCore.this.parseNumber(priceString) );
            put( "baseValue", BitmartCore.this.parseNumber(baseValueString) );
            put( "quoteValue", BitmartCore.this.parseNumber(quoteValueString) );
            put( "timestamp", timestamp );
            put( "datetime", BitmartCore.this.iso8601(timestamp) );
        }});
    }

    /**
     * @method
     * @name bitmart#editOrder
     * @description edits an open order
     * @see https://developer-pro.bitmart.com/en/futuresv2/#modify-plan-order-signed
     * @see https://developer-pro.bitmart.com/en/futuresv2/#modify-tp-sl-order-signed
     * @see https://developer-pro.bitmart.com/en/futuresv2/#modify-preset-plan-order-signed
     * @see https://developer-pro.bitmart.com/en/futuresv2/#modify-limit-order-signed
     * @param {string} id order id
     * @param {string} symbol unified symbol of the market to edit an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} [amount] how much you want to trade in units of the base currency
     * @param {float} [price] the price to fulfill the order, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.triggerPrice] *swap only* the price to trigger a stop order
     * @param {string} [params.stopLossPrice] *swap only* the price to trigger a stop-loss order
     * @param {string} [params.takeProfitPrice] *swap only* the price to trigger a take-profit order
     * @param {string} [params.stopLoss.triggerPrice] *swap only* the price to trigger a preset stop-loss order
     * @param {string} [params.takeProfit.triggerPrice] *swap only* the price to trigger a preset take-profit order
     * @param {string} [params.clientOrderId] client order id of the order
     * @param {int} [params.price_type] *swap only* 1: last price, 2: fair price, default is 1
     * @param {int} [params.plan_category] *swap tp/sl only* 1: tp/sl, 2: position tp/sl, default is 1
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> editOrder(Object id2, Object symbol, Object type2, Object side, Object... optionalArgs)
    {
        final Object id3 = id2;
        final Object type3 = type2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object id = id3;
            Object type = type3;
            Object amount = Helpers.getArg(optionalArgs, 0, null);
            Object price = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            if (!Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(this.id, " editOrder() does not support "), Helpers.GetValue(market, "type")), " markets, only swap markets are supported")) ;
            }
            Object stopLossPrice = this.safeString(parameters, "stopLossPrice");
            Object takeProfitPrice = this.safeString(parameters, "takeProfitPrice");
            Object triggerPrice = this.safeStringN(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("triggerPrice", "stopPrice", "trigger_price")));
            Object stopLoss = this.safeDict(parameters, "stopLoss", new java.util.HashMap<String, Object>() {{}});
            Object takeProfit = this.safeDict(parameters, "takeProfit", new java.util.HashMap<String, Object>() {{}});
            Object presetStopLoss = this.safeString(stopLoss, "triggerPrice");
            Object presetTakeProfit = this.safeString(takeProfit, "triggerPrice");
            Object isTriggerOrder = !Helpers.isEqual(triggerPrice, null);
            Object isStopLoss = !Helpers.isEqual(stopLossPrice, null);
            Object isTakeProfit = !Helpers.isEqual(takeProfitPrice, null);
            Object isPresetStopLoss = !Helpers.isEqual(presetStopLoss, null);
            Object isPresetTakeProfit = !Helpers.isEqual(presetTakeProfit, null);
            Object isLimitOrder = (Helpers.isEqual(type, "limit"));
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object clientOrderId = this.safeString(parameters, "clientOrderId");
            if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
            {
                parameters = this.omit(parameters, "clientOrderId");
                Helpers.addElementToObject(request, "client_order_id", clientOrderId);
            }
            if (Helpers.isTrue(!Helpers.isEqual(id, null)))
            {
                Helpers.addElementToObject(request, "order_id", id);
            }
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("triggerPrice", "stopPrice", "stopLossPrice", "takeProfitPrice", "stopLoss", "takeProfit")));
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(isTriggerOrder) || Helpers.isTrue(isStopLoss)) || Helpers.isTrue(isTakeProfit)))
            {
                Helpers.addElementToObject(request, "price_type", this.safeInteger(parameters, "price_type", 1));
                if (Helpers.isTrue(!Helpers.isEqual(price, null)))
                {
                    Helpers.addElementToObject(request, "executive_price", this.priceToPrecision(symbol, price));
                }
            }
            if (Helpers.isTrue(isTriggerOrder))
            {
                Helpers.addElementToObject(request, "type", type);
                Helpers.addElementToObject(request, "trigger_price", this.priceToPrecision(symbol, triggerPrice));
                response = (this.privatePostContractPrivateModifyPlanOrder(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isTrue(isStopLoss) || Helpers.isTrue(isTakeProfit)))
            {
                Helpers.addElementToObject(request, "category", type);
                if (Helpers.isTrue(isStopLoss))
                {
                    Helpers.addElementToObject(request, "trigger_price", this.priceToPrecision(symbol, stopLossPrice));
                } else
                {
                    Helpers.addElementToObject(request, "trigger_price", this.priceToPrecision(symbol, takeProfitPrice));
                }
                response = (this.privatePostContractPrivateModifyTpSlOrder(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isTrue(isPresetStopLoss) || Helpers.isTrue(isPresetTakeProfit)))
            {
                if (Helpers.isTrue(isPresetStopLoss))
                {
                    Helpers.addElementToObject(request, "preset_stop_loss_price_type", this.safeInteger(parameters, "price_type", 1));
                    Helpers.addElementToObject(request, "preset_stop_loss_price", this.priceToPrecision(symbol, presetStopLoss));
                } else
                {
                    Helpers.addElementToObject(request, "preset_take_profit_price_type", this.safeInteger(parameters, "price_type", 1));
                    Helpers.addElementToObject(request, "preset_take_profit_price", this.priceToPrecision(symbol, presetTakeProfit));
                }
                response = (this.privatePostContractPrivateModifyPresetPlanOrder(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(isLimitOrder))
            {
                Helpers.addElementToObject(request, "order_id", this.parseToInt(id)); // reparse id as int this endpoint is the only one requiring it
                if (Helpers.isTrue(!Helpers.isEqual(amount, null)))
                {
                    Helpers.addElementToObject(request, "size", this.amountToPrecision(symbol, amount));
                }
                if (Helpers.isTrue(!Helpers.isEqual(price, null)))
                {
                    Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
                }
                response = (this.privatePostContractPrivateModifyLimitOrder(this.extend(request, parameters))).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(this.id, " editOrder() only supports limit, trigger, stop loss and take profit orders")) ;
            }
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            return this.parseOrder(data, market);
        });

    }

    /**
     * @method
     * @name bitmart#fetchLedger
     * @description fetch the history of changes, actions done by the user or operations that altered the balance of the user
     * @see https://developer-pro.bitmart.com/en/futuresv2/#get-transaction-history-keyed
     * @param {string} [code] unified currency code
     * @param {int} [since] timestamp in ms of the earliest ledger entry
     * @param {int} [limit] max number of ledger entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms of the latest ledger entry
     * @returns {object[]} a list of [ledger structures]{@link https://docs.ccxt.com/?id=ledger-entry-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchLedger(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object code = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = null;
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                currency = this.currency(code);
            }
            Object request = new java.util.HashMap<String, Object>() {{}};
            var requestparametersVariable = this.handleUntilOption("end_time", request, parameters);
            request = ((java.util.List<Object>) requestparametersVariable).get(0);
            parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
            Object transactionsRequest = this.fetchTransactionsRequest(0, null, since, limit, parameters);
            Object response = (this.privateGetContractPrivateTransactionHistory(transactionsRequest)).join();
            //
            //     {
            //         "code": 1000,
            //         "message": "Ok",
            //         "data": [
            //             {
            //                 "time": "1734422402121",
            //                 "type": "Funding Fee",
            //                 "amount": "-0.00008253",
            //                 "asset": "USDT",
            //                 "symbol": "LTCUSDT",
            //                 "tran_id": "1734422402121",
            //                 "flow_type": 3
            //             },
            //         ],
            //         "trace": "4cd11f83c71egfhfgh842790f07241e.23.173442343427772866"
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseLedger(data, currency, since, limit);
        });

    }

    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        //     {
        //         "time": "1734422402121",
        //         "type": "Funding Fee",
        //         "amount": "-0.00008253",
        //         "asset": "USDT",
        //         "symbol": "LTCUSDT",
        //         "tran_id": "1734422402121",
        //         "flow_type": 3
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object amount = this.safeString(item, "amount");
        Object direction = null;
        if (Helpers.isTrue(Precise.stringLe(amount, "0")))
        {
            direction = "out";
            amount = Precise.stringMul("-1", amount);
        } else
        {
            direction = "in";
        }
        Object currencyId = this.safeString(item, "asset");
        currency = this.safeCurrency(currencyId, currency);
        Object timestamp = this.safeInteger(item, "time");
        Object type = this.safeString(item, "type");
        final Object finalDirection = direction;
        final Object finalCurrency = currency;
        final Object finalAmount = amount;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", BitmartCore.this.safeString(item, "tran_id") );
            put( "direction", finalDirection );
            put( "account", null );
            put( "referenceAccount", null );
            put( "referenceId", BitmartCore.this.safeString(item, "tradeId") );
            put( "type", BitmartCore.this.parseLedgerEntryType(type) );
            put( "currency", Helpers.GetValue(finalCurrency, "code") );
            put( "amount", BitmartCore.this.parseNumber(finalAmount) );
            put( "timestamp", timestamp );
            put( "datetime", BitmartCore.this.iso8601(timestamp) );
            put( "before", null );
            put( "after", null );
            put( "status", null );
            put( "fee", null );
        }}, currency);
    }

    public Object parseLedgerEntryType(Object type)
    {
        Object ledgerType = new java.util.HashMap<String, Object>() {{
            put( "Commission Fee", "fee" );
            put( "Funding Fee", "fee" );
            put( "Realized PNL", "trade" );
            put( "Transfer", "transfer" );
            put( "Liquidation Clearance", "settlement" );
        }};
        return this.safeString(ledgerType, type, type);
    }

    public Object fetchTransactionsRequest(Object... optionalArgs)
    {
        Object flowType = Helpers.getArg(optionalArgs, 0, null);
        Object symbol = Helpers.getArg(optionalArgs, 1, null);
        Object since = Helpers.getArg(optionalArgs, 2, null);
        Object limit = Helpers.getArg(optionalArgs, 3, null);
        Object parameters = Helpers.getArg(optionalArgs, 4, new java.util.HashMap<String, Object>() {{}});
        Object request = new java.util.HashMap<String, Object>() {{}};
        if (Helpers.isTrue(!Helpers.isEqual(flowType, null)))
        {
            Helpers.addElementToObject(request, "flow_type", flowType);
        }
        Object market = null;
        if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
        {
            market = this.market(symbol);
            Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
        }
        if (Helpers.isTrue(!Helpers.isEqual(since, null)))
        {
            Helpers.addElementToObject(request, "start_time", since);
        }
        if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
        {
            Helpers.addElementToObject(request, "page_size", limit);
        }
        var requestparametersVariable = this.handleUntilOption("end_time", request, parameters);
        request = ((java.util.List<Object>) requestparametersVariable).get(0);
        parameters = ((java.util.List<Object>) requestparametersVariable).get(1);
        return this.extend(request, parameters);
    }

