    public Object parseFundingHistories(Object contracts, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object since = Helpers.getArg(optionalArgs, 1, null);
        Object limit = Helpers.getArg(optionalArgs, 2, null);
        Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(contracts)); i++)
        {
            Object contract = Helpers.GetValue(contracts, i);
            ((java.util.List<Object>)result).add(this.parseFundingHistory(contract, market));
        }
        Object sorted = this.sortBy(result, "timestamp");
        return this.filterBySinceLimit(sorted, since, limit);
    }

    public java.util.concurrent.CompletableFuture<Object> fetchWithdrawAddresses(Object code2, Object... optionalArgs)
    {
        final Object code3 = code2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object code = code3;
            Object note = Helpers.getArg(optionalArgs, 0, null);
            Object networkCode = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object codes = null;
            if (Helpers.isTrue(!Helpers.isEqual(code, null)))
            {
                Object currency = this.currency(code);
                code = Helpers.GetValue(currency, "code");
                codes = new java.util.ArrayList<Object>(java.util.Arrays.asList(code));
            }
            Object response = (this.privateGetAccountV1WithdrawAddressList(parameters)).join();
            //
            //     {
            //         "message": "OK",
            //         "code": 1000,
            //         "trace": "0e6edd79-f77f-4251-abe5-83ba75d06c1a",
            //         "data": {
            //             "list": [
            //                 {
            //                     "currency": "ETH",
            //                     "network": "ETH",
            //                     "address": "0x1121",
            //                     "memo": "12",
            //                     "remark": "12",
            //                     "addressType": 0,
            //                     "verifyStatus": 0
            //                 }
            //             ]
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object list = this.safeList(data, "list", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object allAddresses = this.parseDepositAddresses(list, codes, false);
            Object addresses = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(allAddresses)); i++)
            {
                Object address = Helpers.GetValue(allAddresses, i);
                Object noteMatch = Helpers.isTrue((Helpers.isEqual(note, null))) || Helpers.isTrue((Helpers.isEqual(Helpers.GetValue(address, "note"), note)));
                Object networkMatch = Helpers.isTrue((Helpers.isEqual(networkCode, null))) || Helpers.isTrue((Helpers.isEqual(Helpers.GetValue(address, "network"), networkCode)));
                if (Helpers.isTrue(Helpers.isTrue(noteMatch) && Helpers.isTrue(networkMatch)))
                {
                    ((java.util.List<Object>)addresses).add(address);
                }
            }
            return addresses;
        });

    }

